def update_account_balance(transactions, account_balances):
    if not isinstance(transactions, list) or not isinstance(account_balances, dict):
        raise ValueError("Invalid input types. 'transactions' must be a list and 'account_balances' must be a dictionary.")

    for transaction in transactions:
        if not isinstance(transaction, dict):
            raise ValueError("Each transaction must be a dictionary.")
        
        account_id = transaction.get('account_id')
        amount = transaction.get('amount')

        if account_id is None or amount is None:
            raise ValueError("Each transaction must contain 'account_id' and 'amount'.")

        if account_id not in account_balances:
            raise ValueError(f"Account ID {account_id} does not exist.")

        if not isinstance(amount, (int, float)):
            raise ValueError("Transaction amount must be a number.")

        account_balances[account_id] += amount

    return account_balances

